SELECT
FROM sys_department d WHERE d.is_deleted = 0
AND d.dept_name LIKE CONCAT('%', #{req.keyword}, '%')
AND d.parent_id = #{req.parentDeptId}
AND d.status = #{statusCode}
ORDER BY d.sort ASC, d.dept_id ASC

SELECT COUNT(1)
FROM sys_department d
WHERE d.dept_name = #{deptName}
  AND d.is_deleted = 0

    AND d.parent_id IS NULL


    AND d.parent_id = #{parentDeptId}


    AND d.dept_id != #{excludeDeptId}

SELECT MAX(d.sort) FROM sys_department d WHERE d.is_deleted = 0
AND d.parent_id IS NULL
AND d.parent_id = #{parentDeptId}
